void streamCluster( PStream* stream,
                    long kmin, long kmax, int dim,
                    long chunksize, long centersize, char* outfile )
{

  float* block = (float*)malloc( chunksize*dim*sizeof(float) );
  float* centerBlock = (float*)malloc(centersize*dim*sizeof(float) );
  long* centerIDs = (long*)malloc(centersize*dim*sizeof(long));

  if( block == NULL ) {
    fprintf(stderr,"not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize*sizeof(Point));
  for( int i = 0; chunksize > i; i++ ) {
    points.p[i].coord = &block[i*dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize*sizeof(Point));
  centers.num = 0;

  for( int i = 0; centersize > i; i++ ) {
    centers.p[i].coord = &centerBlock[i*dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while(1) {

    size_t numRead  = stream->read(block, dim, chunksize );
    fprintf(stderr,"read %lu points\n",numRead);

    if( stream->ferror() || (unsigned int)chunksize > numRead && !stream->feof() ) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for( int i = 0; points.num > i; i++ ) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (char*)malloc(points.num*sizeof(char));
    is_center = (bool*)calloc(points.num,sizeof(bool));
    center_table = (int*)malloc(points.num*sizeof(int));

    localSearch(&points,kmin, kmax,&kfinal);

    fprintf(stderr,"finish local search\n");
    contcenters(&points);
    if( centersize < kfinal + centers.num ) {

      fprintf(stderr,"oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset = IDoffset + (numRead);

#ifdef PRINTINFO
    printf("finish copy centers\n");
#endif
    free(is_center);
    free(switch_membership);
    free(center_table);
    if( stream->feof() ) {
      break;
    }
  }

  switch_membership = (char*)malloc(centers.num*sizeof(char));
  is_center = (bool*)calloc(centers.num,sizeof(bool));
  center_table = (int*)malloc(centers.num*sizeof(int));

  localSearch( &centers, kmin, kmax ,&kfinal );
  contcenters(&centers);
  outcenterIDs( &centers, centerIDs, outfile);
}

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

static int c = 0;
static float *work_mem_h;
static float *coord_h;
static float *gl_lower;
static Point_Struct *p_h;

static float *work_mem_d;
static float *coord_d;
static int *center_table_d;
static char *switch_membership_d;
static Point_Struct *p_d;

void checkCudaError(cudaError_t err, const char* msg) {
  if (err != cudaSuccess) {
    fprintf(stderr, "%s: %s\n", msg, cudaGetErrorString(err));
    exit(1);
  }
}

void quit(char *message){
  printf("%s\n", message);
  exit(1);
}

void freeDevMem(){
  if(work_mem_d) cudaFree(work_mem_d);
  if(center_table_d) cudaFree(center_table_d);
  if(switch_membership_d) cudaFree(switch_membership_d);
  if(p_d) cudaFree(p_d);
  if(coord_d) cudaFree(coord_d);

  if(work_mem_h) free(work_mem_h);
  if(coord_h) free(coord_h);
  if(gl_lower) free(gl_lower);
  if(p_h) free(p_h);
}

void allocDevMem(int num, int dim, int kmax){
  checkCudaError(cudaMalloc(&work_mem_d, kmax * num * sizeof(float)), "cudaMalloc work_mem_d");
  checkCudaError(cudaMalloc(&center_table_d, num * sizeof(int)), "cudaMalloc center_table_d");
  checkCudaError(cudaMalloc(&switch_membership_d, num * sizeof(char)), "cudaMalloc switch_membership_d");
  checkCudaError(cudaMalloc(&p_d, num * sizeof(Point_Struct)), "cudaMalloc p_d");
  checkCudaError(cudaMalloc(&coord_d, num * dim * sizeof(float)), "cudaMalloc coord_d");
}

__global__ void memset_kernel(char * mem_d, short val, int number_bytes){
  const int thread_id = threadIdx.x + blockIdx.x * blockDim.x;
  if(thread_id < number_bytes) {
    mem_d[thread_id] = val;
  }
}

__global__ void pgain_kernel(
    Point_Struct *p,
    float *coord_d,
    float * work_mem_d,
    int *center_table_d,
    char *switch_membership_d,
    float *coord_s,
    int num,
    int dim,
    long x,
    int K){

  const int thread_id = threadIdx.x + blockIdx.x * blockDim.x;
  const int local_id = threadIdx.x;

  if(thread_id < num){

    if(0 == local_id) {
      for(int i=0; i<dim; i++){
        coord_s[i] = coord_d[i*num + x];
      }
    }
    __syncthreads();

    float x_cost = 0.0;
    for(int i=0; i<dim; i++)
      x_cost += (coord_d[(i*num)+thread_id]-coord_s[i]) * (coord_d[(i*num)+thread_id]-coord_s[i]);
    x_cost = x_cost * p[thread_id].weight;

    float current_cost = p[thread_id].cost;

    int base = thread_id*(K+1);

    if ( current_cost > x_cost ){
      switch_membership_d[thread_id] = '1';
      int addr_1 = base + K;
      work_mem_d[addr_1] = x_cost - current_cost;
    }
    else {
      int assign = p[thread_id].assign;
      int addr_2 = base + center_table_d[assign];
      work_mem_d[addr_2] += current_cost - x_cost;
    }
  }
}

float pgain_cuda( long x, Points *points, float z, long *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
                  double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel){
  float gl_cost = 0;
  try{
#ifdef PROFILE_TMP
    double t1 = gettime();
#endif
    int K = *numcenters ;
    int num    =   points->num;
    int dim     =   points->dim;
    kmax++;

    int count = 0;
    for( int i=0; i<num; i++){
      if( is_center[i] )
        center_table[i] = count++;
    }

#ifdef PROFILE_TMP
    double t2 = gettime();
    *serial += t2 - t1;
#endif

    if( c == 0 ) {
#ifdef PROFILE_TMP
      double t3 = gettime();
#endif
      coord_h = (float*) malloc( num * dim * sizeof(float));
      gl_lower = (float*) malloc( kmax * sizeof(float) );
#ifdef  TIMING
      gettimeofday(&tv_mem_alloc_start, NULL);
#endif
      work_mem_h = (float*)malloc(kmax*num*sizeof(float));
#ifdef  TIMING
      gettimeofday(&tv_mem_alloc_end, NULL);
      tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
      mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

      p_h = (Point_Struct*)malloc(num*sizeof(Point_Struct));

      for(int i=0; i<dim; i++){
        for(int j=0; j<num; j++)
          coord_h[ (num*i)+j ] = points->p[j].coord[i];
      }
#ifdef PROFILE_TMP
      double t4 = gettime();
      *serial += t4 - t3;
#endif
#ifdef  TIMING
      gettimeofday(&tv_mem_alloc_start, NULL);
#endif

      allocDevMem(num, dim, kmax);
#ifdef  TIMING
      gettimeofday(&tv_mem_alloc_end, NULL);
      tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
      mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
#ifdef PROFILE_TMP
      double t5 = gettime();
      *gpu_malloc += t5 - t4;
#endif

      checkCudaError(cudaMemcpy(coord_d, coord_h, num*dim*sizeof(float), cudaMemcpyHostToDevice), "cudaMemcpy coord_h -> coord_d");
#ifdef PROFILE_TMP
      double t6 = gettime();
      *cpu_gpu_memcpy += t6 - t5;
#endif
    }
#ifdef PROFILE_TMP
    double t100 = gettime();
#endif

    for(int i=0; i<num; i++){
      p_h[i].weight = ((points->p)[i]).weight;
      p_h[i].assign = ((points->p)[i]).assign;
      p_h[i].cost = ((points->p)[i]).cost;
    }

#ifdef PROFILE_TMP
    double t101 = gettime();
    *serial += t101 - t100;
#endif
#ifdef PROFILE_TMP
    double t7 = gettime();
#endif

    checkCudaError(cudaMemcpy(center_table_d,  center_table, num*sizeof(int), cudaMemcpyHostToDevice), "cudaMemcpy center_table");
    checkCudaError(cudaMemcpy(p_d,  p_h,  num * sizeof(Point_Struct), cudaMemcpyHostToDevice), "cudaMemcpy p_h");
#ifdef PROFILE_TMP
    double t8 = gettime();
    *cpu_gpu_memcpy += t8 - t7;
#endif

    size_t smSize = dim * sizeof(float);
#ifdef PROFILE_TMP
    double t9 = gettime();
#endif
    int blocks = (num + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK;
    memset_kernel<<<blocks, THREADS_PER_BLOCK>>>(switch_membership_d, 0, num*sizeof(char));
    cudaDeviceSynchronize();
    memset_kernel<<<blocks, THREADS_PER_BLOCK>>>(work_mem_d, 0, (K+1)*num*sizeof(float));
    cudaDeviceSynchronize();

    dim3 blockDim(THREADS_PER_BLOCK);
    dim3 blockDim2D((num + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK, 1);

#ifdef PROFILE_TMP
    double t9_start = gettime();
#endif
    pgain_kernel<<<blockDim2D, blockDim, smSize>>>(
        p_d,
        coord_d,
        work_mem_d,
        center_table_d,
        switch_membership_d,
        NULL, 
        num,
        dim,
        x,
        K);
    cudaDeviceSynchronize();

#ifdef PROFILE_TMP
    double t10 = gettime();
    *kernel += t10 - t9;
#endif

    checkCudaError(cudaMemcpy(switch_membership, switch_membership_d, num * sizeof(char), cudaMemcpyDeviceToHost), "cudaMemcpy switch_membership");
    checkCudaError(cudaMemcpy(work_mem_h, work_mem_d, (K+1) *num*sizeof(float), cudaMemcpyDeviceToHost), "cudaMemcpy work_mem");

#ifdef PROFILE_TMP
    double t11 = gettime();
    *memcpy_back += t11 - t10;
#endif

    int numclose = 0;
    gl_cost = z;

    for(int i=0; i < num; i++){
      if( is_center[i] ) {
        float low = z;

        for( int j = 0; j < num; j++ )
          low += work_mem_h[ j*(K+1) + center_table[i] ];

        gl_lower[center_table[i]] = low;

        if ( low > 0 ) {
          numclose++;
          work_mem_h[i*(K+1)+K] -= low;
        }
      }
      gl_cost += work_mem_h[i*(K+1)+K];
    }

    if ( gl_cost < 0 ) {
      for(int i=0; i<num; i++){

        bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
        if ( (switch_membership[i]=='1') || close_center ) {
          points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
          points->p[i].assign = x;
        }
      }

      for(int i=0; i<num; i++){
        if( is_center[i] && gl_lower[center_table[i]] > 0 )
          is_center[i] = false;
      }

      is_center[x] = true;
      *numcenters = *numcenters +1 - numclose;
    }
    else
      gl_cost = 0;

#ifdef PROFILE_TMP
    double t12 = gettime();
    *serial += t12 - t11;
#endif
    c++;
  }
  catch(string msg){
    printf("--cambine:%s\n", msg.c_str());
    freeDevMem();
    exit(-1);
  }
  catch(...){
    printf("--cambine: unknow reasons in pgain\n");
  }

  return -gl_cost;
}

